"use strict";parserFactory.register("shirokuns.com",()=>new ShirokunsParser);class ShirokunsParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("div.blog-post li a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("div.entry-content")}extractTitleImpl(e){return e.querySelector("div.main h1")}preprocessRawDom(e){util.removeChildElementsMatchingSelector(e,"p.author, div.col-md-12 img")}findCoverImageUrl(e){let r=e.querySelector("article p img");return null===r?null:r.src}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div#editdescription")]}}